Rule.Source:

import java.util.HashMap;
import sailpoint.object.Custom;
import sailpoint.object.Identity;

import org.apache.log4j.Logger; 
import org.apache.log4j.Level;
import org.apache.commons.logging.LogFactory;

Logger azLog = Logger.getLogger("rule.Rule-AzureADCorrelation");
azLog.trace("AADC-001: Executing Rule Rule-AzureADCorrelation");

String guidAttributeName = "";
String guidAttributeValue = "";
String workdayIdAttrName = "";
String workdayIdAttrValue = "";
String mailNickname = "";

Map returnMap = new HashMap();

// Get attributes for matching
try {
  // Get extension attribute names from the custom object
  Custom extensionAttributesCustomObject = context.getObjectByName( Custom.class, "Azure Extension Attributes" );
  if ( extensionAttributesCustomObject != null ) {
    guidAttributeName = extensionAttributesCustomObject.getString( "guid" );
    workdayIdAttrName = extensionAttributesCustomObject.getString( "workdayID" );
  } else {
    guidAttributeName = "extensionAttribute2";
  }

  guidAttributeValue = account.getStringAttribute( guidAttributeName );
  workdayIdAttrValue = account.getStringAttribute( workdayIdAttrName );
  mailNickname = account.getStringAttribute( "mailNickname" );

  azLog.trace( "AADC-002: Matching Attribtues: \n"  +
               "guid: "         + guidAttributeValue + "\n" +
               "WorkdayID: "    + workdayIdAttrValue + "\n" + 
               "mailNickname: " + mailNickname + "\n"
  );

  // Match on Identity Name for Privileged accounts
  //Removing Privileged accounts condition as new application has been created for Privileged accounts
  if( guidAttributeValue == null || guidAttributeValue.isEmpty() ) {
    azLog.trace( "AADC-005: Non Privileged Account and GUID null" );
    if ( workdayIdAttrValue != null && !workdayIdAttrValue.isEmpty() ) {
      returnMap.put( "identityAttributeName", "workday_id" );
      returnMap.put( "identityAttributeValue", workdayIdAttrValue );
    }
  } else {
    azLog.trace( "AADC-008: Non Privileged Account and GUID not null" );
    returnMap.put( "identityAttributeName", "guid" );
    returnMap.put( "identityAttributeValue", guidAttributeValue );
  }
} catch ( Exception ex ) {
  azLog.trace( "AADC-003: ERROR:: retreiving attribute(s) " + ex );
}

azLog.trace( "AADC-006: Correlation Map for "+account.getStringAttribute( "objectId" )+" is--- " + returnMap.toString() );
azLog.trace( "AADC-007: Exiting Rule Rule-AzureADCorrelation for "+account.getStringAttribute( "userPrincipalName" ) );

return returnMap;
